\begin {tikzpicture}[auto]
  \node  (v1) at (0,3) {$v_{1}$: $p$ off, $q$ off};
  \node  (v2) at (5,3) {$v_{2}$: $p$ on, $q$ off};
  \node  (v3) at (0,0) {$v_{3}$: $p$ off, $q$ on};
  \node  (v4) at (5,0) {$v_{4}$: $p$ on, $q$ on};
  \draw  (v1) to node {switch $p$} (v2);
  \draw  (v2) to node {switch $q$} (v4);
  \draw  (v1) to node {switch $q$} (v3);
  \draw  (v3) to node {switch $p$} (v4);


\end {tikzpicture}
